const uniqueIds = new Set();
const uniqueRecords = [];

for (const item of items) {
  // Check if we've already added this Airtable record ID
  if (!uniqueIds.has(item.json.id)) {
    uniqueIds.add(item.json.id);
    uniqueRecords.push(item);
  }
}

return uniqueRecords;

